import os
from pathlib import Path

# Scan the src directory to understand actual structure
src_path = Path("/mnt/kimi/upload/src")

if not src_path.exists():
    # Try to find src anywhere in upload
    for root, dirs, files in os.walk("/mnt/kimi/upload"):
        if "src" in dirs:
            src_path = Path(os.path.join(root, "src"))
            break

print(f"Scanning: {src_path}")
print("="*80)

if src_path.exists():
    # Get directory structure
    structure = {}
    qt_files = []
    noqt_files = []
    h_files = []
    cpp_files = []
    asm_files = []
    
    for root, dirs, files in os.walk(src_path):
        rel_root = os.path.relpath(root, src_path)
        if rel_root == '.':
            rel_root = ''
        
        for file in files:
            filepath = os.path.join(root, file)
            rel_path = os.path.relpath(filepath, src_path)
            
            if file.endswith(('.h', '.hpp')):
                h_files.append(rel_path)
            elif file.endswith(('.cpp', '.cc')):
                cpp_files.append(rel_path)
            elif file.endswith('.asm'):
                asm_files.append(rel_path)
            
            # Check for Qt
            if file.endswith(('.h', '.hpp', '.cpp', '.cc')):
                try:
                    with open(filepath, 'r', encoding='utf-8', errors='ignore') as f:
                        content = f.read()
                        if any(qt in content for qt in ['#include <Q', '#include "Q', 'QT_', 'QObject', 'QWidget', 'QMainWindow', 'QApplication']):
                            qt_files.append(rel_path)
                        elif 'noqt' in file.lower() or 'no_qt' in content.lower():
                            noqt_files.append(rel_path)
                except Exception as e:
                    pass
    
    print(f"\nрџ“Ѓ SOURCE STRUCTURE")
    print(f"   Headers (.h/.hpp): {len(h_files)}")
    print(f"   Source (.cpp/.cc): {len(cpp_files)}")
    print(f"   Assembly (.asm):   {len(asm_files)}")
    print(f"   Total: {len(h_files) + len(cpp_files) + len(asm_files)}")
    
    print(f"\nрџ”ґ QT FILES: {len(qt_files)}")
    for f in sorted(qt_files)[:20]:
        print(f"   {f}")
    if len(qt_files) > 20:
        print(f"   ... and {len(qt_files) - 20} more")
    
    print(f"\nрџџў NO-QT FILES (Pattern): {len(noqt_files)}")
    for f in sorted(noqt_files):
        print(f"   {f}")
    
    # Get directory listing
    print(f"\nрџ“‚ DIRECTORY STRUCTURE")
    for item in sorted(os.listdir(src_path)):
        full_path = os.path.join(src_path, item)
        if os.path.isdir(full_path):
            count = sum(1 for _, _, files in os.walk(full_path) for f in files if f.endswith(('.h', '.hpp', '.cpp', '.cc', '.asm')))
            print(f"   {item}/ ({count} files)")
else:
    print("вќЊ src directory not found")
    print("\nSearching for any code files...")
    for root, dirs, files in os.walk("/mnt/kimi/upload"):
        code_files = [f for f in files if f.endswith(('.h', '.hpp', '.cpp', '.cc', '.asm'))]
        if code_files:
            print(f"\n{root}:")
            for f in code_files[:5]:
                print(f"   {f}")
            if len(code_files) > 5:
                print(f"   ... and {len(code_files) - 5} more")
