    // Text buffer (rope structure)
    struct TextPiece {
        wchar_t* text;
        int length;
        int capacity;
    };
    Vector<TextPiece> pieces;
    
    // View state
    int scrollX = 0, scrollY = 0;
    int cursorPos = 0;
    int anchorPos = 0;
    int lineHeight = 0;
    int charWidth = 0;
    
    // Rendering
    ID2D1HwndRenderTarget* renderTarget = nullptr;
    IDWriteTextFormat* textFormat = nullptr;
    
    static LRESULT CALLBACK EditProc(HWND, UINT, WPARAM, LPARAM);
    
public:
    bool create(HWND parent);
    void destroy();
    
    // Text operations
    void setText(const String& text);
    String getText() const;
    void insertText(int pos, const String& text);
    void deleteText(int pos, int len);
    
    // Cursor/Selection
    void setCursor(int pos);
    int getCursor() const { return cursorPos; }
    void setSelection(int start, int end);
    bool hasSelection() const { return cursorPos != anchorPos; }
    void deleteSelection();
    String getSelectedText() const;
    
    // Navigation
    void moveCursor(int delta, bool select);
    void moveWord(bool right, bool select);
    void moveLine(bool down, bool select);
    void moveHome(bool select);
    void moveEnd(bool select);
    
    // Editing
    void undo();
    void redo();
    void cut();
    void copy();
    void paste();
    void selectAll();
    
    // View
