    // QString в†’ RAWRXD_String
    class String : public std::wstring {
    public:
        String() = default;
        String(const wchar_t* s) : std::wstring(s) {}
        String(const char* utf8);

        String mid(size_t pos, size_t len = npos) const { return substr(pos, len); }
        int toInt(bool* ok = nullptr) const;
        static String number(int n);
        static String fromUtf8(const char* s);
        std::string toUtf8() const;
    };

    // QByteArray в†’ RAWRXD_ByteArray
    class ByteArray : public std::vector<uint8_t> {
    public:
        ByteArray() = default;
        ByteArray(const char* s) : std::vector<uint8_t>(s, s + strlen(s)) {}
        const char* constData() const { return (const char*)data(); }
    };

    // QList/QVector в†’ RAWRXD_Vector
    template<typename T>
    class Vector : public std::vector<T> {
    public:
        void append(const T& v) { push_back(v); }
        void removeAt(size_t i) { erase(begin() + i); }
        bool contains(const T& v) const { return find(v) != end(); }
    };

    // QMap в†’ RAWRXD_Map
    template<typename K, typename V>
    class Map : public std::map<K, V> {
    public:
        bool contains(const K& k) const { return find(k) != end(); }
        void insert(const K& k, const V& v) { (*this)[k] = v; }
    };

    // QThread в†’ RAWRXD_Thread
    class Thread {
        HANDLE hThread = nullptr;
        static DWORD WINAPI ThreadProc(LPVOID param);
    public:
        void start(std::function<void()> fn);
        void wait();
        bool isRunning() const;
    };

