    class Mutex {
        SRWLOCK lock = SRWLOCK_INIT;
    public:
        void lock() { AcquireSRWLockExclusive(&lock); }
        void unlock() { ReleaseSRWLockExclusive(&lock); }
    };

    // QTimer в†’ RAWRXD_Timer
    class Timer {
        UINT_PTR id = 0;
        std::function<void()> callback;
        static VOID CALLBACK TimerCallback(HWND, UINT, UINT_PTR, DWORD);
    public:
        void start(int msec, std::function<void()> cb);
        void stop();
    };
