    std::string toUtf8() const { return WideToUtf8(data.c_str(), static_cast<int>(data.length())); }
    const wchar_t* constData() const { return data.data(); }
    wchar_t* data_ptr() { return data.data(); }
    
    // Properties
    bool isEmpty() const { return data.empty(); }
